const chatBody = document.getElementById("chat-body");
const input = document.getElementById("chat-input");
const sendBtn = document.getElementById("send-btn");

/* Typing Indicator */
const typingIndicator = document.createElement("div");
typingIndicator.id = "typing-indicator";
typingIndicator.className = "typing-indicator hidden";
typingIndicator.innerHTML = `
  <span class="dot"></span>
  <span class="dot"></span>
  <span class="dot"></span>
`;
chatBody.appendChild(typingIndicator);

/* Add User Message */
function addUserMessage(text) {
  const msgWrapper = document.createElement("div");
  msgWrapper.className = "message user-msg";

  msgWrapper.innerHTML = `
    <div class="message-bubble">${text}</div>
  `;

  chatBody.appendChild(msgWrapper);
  scrollBottom();
}

/* Add Bot Message */
function addBotMessage(text) {
  const msgWrapper = document.createElement("div");
  msgWrapper.className = "message bot-msg";

  msgWrapper.innerHTML = `
    <div class="message-bubble">${text}</div>
  `;

  chatBody.appendChild(msgWrapper);
  scrollBottom();
}

/* Typing Indicator Controls */
function showTyping() {
  typingIndicator.classList.remove("hidden");
  chatBody.appendChild(typingIndicator);
  scrollBottom();
}

function hideTyping() {
  typingIndicator.classList.add("hidden");
}

/* Scroll to bottom */
function scrollBottom() {
  chatBody.scrollTop = chatBody.scrollHeight;
}

/* Send Message */
sendBtn.addEventListener("click", sendMessage);
input.addEventListener("keypress", (e) => {
  if (e.key === "Enter") sendMessage();
});

function sendMessage() {
  const text = input.value.trim();
  if (!text) return;

  addUserMessage(text);
  input.value = "";

  showTyping();

  setTimeout(() => {
    hideTyping();
    addBotMessage(
      "I’m here with you 💜 Take your time. Would you like to tell me more about what’s been on your mind?"
    );
  }, 1500);
}

/* Initial Bot Message */
window.onload = () => {
  addBotMessage(
    "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?"
  );
};
